diff --git a/HelloWorld-CoreML/HelloWorld/HelloWorld/TorchBridge/TorchModule.mm b/HelloWorld-CoreML/HelloWorld/HelloWorld/TorchBridge/TorchModule.mm
new file mode 100644
index 0000000..e6defdf
