diff --git a/HelloWorld-Metal/HelloWorld-Metal/HelloWorld-Metal/TorchBridge/TorchModule.mm b/HelloWorld-Metal/HelloWorld-Metal/HelloWorld-Metal/TorchBridge/TorchModule.mm
new file mode 100644
index 0000000..81ef769
--- /dev/null
+++ b/HelloWorld-Metal/HelloWorld-Metal/HelloWorld-Metal/TorchBridge/TorchModule.mm
@@ -0,0 +1,43 @@
+#import "TorchModule.h"
+#import <LibTorch-Lite-Nightly/LibTorch-Lite.h>
+
+@implementation TorchModule {
+ @protected
+  torch::jit::mobile::Module _impl;
+}
+
+- (nullable instancetype)initWithFileAtPath:(NSString*)filePath {
+  self = [super init];
+  if (self) {
+    try {
+      _impl = torch::jit::_load_for_mobile(filePath.UTF8String);
+    } catch (const std::exception& exception) {
+      NSLog(@"%s", exception.what());
+      return nil;
+    }
+  }
+  return self;
+}
+
+- (NSArray<NSNumber*>*)predictImage:(void*)imageBuffer {
+  try {
+    c10::InferenceMode mode;
+    at::Tensor tensor = torch::from_blob(imageBuffer, {1, 3, 224, 224}, at::kFloat).metal();
+    auto outputTensor = _impl.forward({tensor}).toTensor().cpu();
+    float* floatBuffer = outputTensor.data_ptr<float>();
+    if (!floatBuffer) {
+      return nil;
+    }
+    NSMutableArray* results = [[NSMutableArray alloc] init];
+    for (int i = 0; i < 1000; i++) {
+      [results addObject:@(floatBuffer[i])];
+    }
+    return [results copy];
+  } catch (const std::exception& exception) {
+    NSLog(@"%s", exception.what());
+  }
+  return nil;
+}
+
+@end
+
diff --git a/HelloWorld-Metal/HelloWorld-Metal/HelloWorld-Metal/UIImage+Helper.swift b/HelloWorld-Metal/HelloWorld-Metal/HelloWorld-Metal/UIImage+Helper.swift
new file mode 100755
index 0000000..d8bab86
--- /dev/null
+++ b/HelloWorld-Metal/HelloWorld-Metal/HelloWorld-Metal/UIImage+Helper.swift
@@ -0,0 +1,47 @@
+import UIKit
+
+extension UIImage {
+    func resized(to newSize: CGSize, scale: CGFloat = 1) -> UIImage {
+        let format = UIGraphicsImageRendererFormat.default()
+        format.scale = scale
+        let renderer = UIGraphicsImageRenderer(size: newSize, format: format)
+        let image = renderer.image { _ in
+            draw(in: CGRect(origin: .zero, size: newSize))
+        }
+        return image
+    }
+
+    func normalized() -> [Float32]? {
+        guard let cgImage = self.cgImage else {
+            return nil
+        }
+        let w = cgImage.width
+        let h = cgImage.height
+        let bytesPerPixel = 4
+        let bytesPerRow = bytesPerPixel * w
+        let bitsPerComponent = 8
+        var rawBytes: [UInt8] = [UInt8](repeating: 0, count: w * h * 4)
+        rawBytes.withUnsafeMutableBytes { ptr in
+            if let cgImage = self.cgImage,
+                let context = CGContext(data: ptr.baseAddress,
+                                        width: w,
+                                        height: h,
+                                        bitsPerComponent: bitsPerComponent,
+                                        bytesPerRow: bytesPerRow,
+                                        space: CGColorSpaceCreateDeviceRGB(),
+                                        bitmapInfo: CGImageAlphaInfo.premultipliedLast.rawValue) {
+                let rect = CGRect(x: 0, y: 0, width: w, height: h)
+                context.draw(cgImage, in: rect)
+            }
+        }
+        var normalizedBuffer: [Float32] = [Float32](repeating: 0, count: w * h * 3)
+        // normalize the pixel buffer
+        // see https://pytorch.org/hub/pytorch_vision_resnet/ for more detail
+        for i in 0 ..< w * h {
+            normalizedBuffer[i] = (Float32(rawBytes[i * 4 + 0]) / 255.0 - 0.485) / 0.229 // R
+            normalizedBuffer[w * h + i] = (Float32(rawBytes[i * 4 + 1]) / 255.0 - 0.456) / 0.224 // G
+            normalizedBuffer[w * h * 2 + i] = (Float32(rawBytes[i * 4 + 2]) / 255.0 - 0.406) / 0.225 // B
+        }
+        return normalizedBuffer
+    }
+}
