diff --git a/HelloWorldMetal/HelloWorldMetal/HelloWorldMetal/TorchBridge/TorchModule.mm b/HelloWorldMetal/HelloWorldMetal/HelloWorldMetal/TorchBridge/TorchModule.mm
new file mode 100644
